#include <stdio.h>
#include <limits.h>

int max(int a, int b) { return a > b ? a : b; }

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int R, C, I;
        scanf("%d %d %d", &R, &C, &I);
        int A[R][C];
        if (I == 1) {
            for (int i = 0; i < R; i++) {
                for (int j = 0; j < C; j++) {
                    scanf("%d", &A[i][j]);
                }
            }
        } else {
            int X, P, Q, M;
            scanf("%d %d %d %d", &X, &P, &Q, &M);
            int cur = X;
            for (int i = 0; i < R; i++) {
                for (int j = 0; j < C; j++) {
                    cur = (cur * P + Q) % M;
                    A[i][j] = X - cur;
                }
            }
        }
        int dp[R][C];
        for (int i = 0; i < R; i++) {
            for (int j = 0; j < C; j++) {
                dp[i][j] = A[i][j];
            }
        }
        for (int i = 1; i < R; i++) {
            for (int j = 0; j < C; j++) {
                int max_sum = INT_MIN;
                if (j > 0) max_sum = max(max_sum, dp[i-1][j-1]);
                max_sum = max(max_sum, dp[i-1][j]);
                if (j < C - 1) max_sum = max(max_sum, dp[i-1][j+1]);
                dp[i][j] += max_sum;
            }
        }
        int max_sum = INT_MIN;
        for (int j = 0; j < C; j++) {
            max_sum = max(max_sum, dp[R-1][j]);
        }
        printf("%d\n", max_sum);
    }
    return 0;
}

