                int X = sc.nextInt();
                int P = sc.nextInt();
                int Q = sc.nextInt();
                int M = sc.nextInt();
                int cur = X;
                for (int i = 0; i < R; i++) {
                    for (int j = 0; j < C; j++) {
                        cur = (cur * P + Q) % M;
                        A[i][j] = X - cur;
                    }
                }
            }
            int[][] dp = new int[R][C];
            for (int i = 0; i < R; i++) {
                for (int j = 0; j < C; j++) {
                    dp[i][j] = A[i][j];
                }
            }
            for (int i = 1; i < R; i++) {
                for (int j = 0; j < C; j++) {
                    int max_sum = Integer.MIN_VALUE;
