    let [R, C, I] = nextInts();
    let A = Array(R).fill(0).map(() => Array(C).fill(0));
    if (I == 1) {
        for (let i = 0; i < R; i++) {
            let row = nextInts();
            for (let j = 0; j < C; j++) {
                A[i][j] = row[j];
            }
        }
    } else {
        let [X, P, Q, M] = nextInts();
        let cur = X;
        for (let i = 0; i < R; i++) {
            for (let j = 0; j < C; j++) {
                cur = (cur * P + Q) % M;
                A[i][j] = X - cur;
            }
        }
    }
    let dp = Array(R).fill(0).map(() => Array(C).fill(0));
    for (let i = 0; i < R; i++) {
        for (let j = 0; j < C; j++) {
            dp[i][j] = A[i][j];
        }
